import numpy as np

def calculate_distance(pos1, pos2, truck_speed):
    distance = np.linalg.norm(pos1 - pos2)
    return distance / truck_speed

def calculate_penalty(arrival_time, time_window):
    if arrival_time < time_window[0]:
        return time_window[0] - arrival_time
    elif arrival_time > time_window[1]:
        return arrival_time - time_window[1]
    else:
        return 0

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    best_score = float('inf')

    for i, customer in enumerate(unvisited_customers):
        arrival_time = current_time + calculate_distance(cur_truck_pos, customer, truck_speed)
        penalty = calculate_penalty(arrival_time, time_windows[i])

        if penalty <= 0:
            score = arrival_time
        else:
            wait_time = penalty / 2
            score = arrival_time + wait_time

        if score < best_score:
            best_score = score
            best_node = i

    return best_node
